INSERT IGNORE INTO `actividad` VALUES (5,5,'Tour Básico','Catamarán, snorkel y tiempo libre en la isla',1200.00,'8 horas','09:00'),(6,5,'Tour Premium','Incluye comida gourmet, barra premium y masaje',2500.00,'8 horas','10:30'),(7,6,'Senderismo Guiado','Recorrido para avistar fauna local',0.00,'1 hora','Sáb-Dom: 08:00 y 10:00'),(8,8,'Tour Educativo','Aprende sobre el ecosistema local y el cenote',100.00,'1.5 horas','Sáb: 10:00'),(9,14,'Tour Gastronómico','Recorrido por los mejores puestos de comida del mercado con degustaciones incluidas',350.00,'2 horas','Lun-Sáb 10:00 y 14:00'),(10,14,'Taller de Artesanías','Aprende a hacer artesanías mayas con artesanos locales',200.00,'1.5 horas','Mar y Jue 11:00'),(11,15,'Clase de Salsa','Clase grupal de salsa y bachata al aire libre',0.00,'1 hora','Vie-Sáb 19:00'),(12,15,'Cine al Aire Libre','Proyección de películas gratuita en la plaza principal',0.00,'2 horas','Sáb 20:00'),(16,18,'Snorkel en Arrecife','Snorkel guiado en el arrecife de Isla Mujeres con equipo incluido',450.00,'1.5 horas','Diario 10:00 y 14:00'),(17,18,'Paddleboard al Atardecer','Renta de paddleboard con vista al atardecer caribeño',350.00,'1 hora','Diario 17:00-19:00'),(18,19,'Visita Guiada Arqueológica','Recorrido con guía experto por las salas del museo y zona arqueológica San Miguelito',200.00,'2 horas','Mar-Dom 10:00 y 14:00'),(24,2,'Noche de Tacos al Pastor','Tacos ilimitados al pastor con salsa especial de la casa',180.00,'1 hora','Mar-Dom 18:00-23:00'),(25,3,'Tarde de Café y Arte','Taller de latte art con barista profesional',250.00,'1.5 horas','Sáb 16:00'),(26,7,'Yoga al Amanecer','Clase de yoga frente al mar con instructor certificado',150.00,'1 hora','Lun-Vie 6:30'),(30,22,'Degustación de Mariscos','Prueba los platillos icónicos: ceviche, aguachile y pescado zarandeado con salsas de la casa',350.00,'1 hora','Mar-Dom 12:00-16:00'),(31,24,'Taller de Cochinita Pibil','Aprende a preparar cochinita pibil tradicional con técnicas ancestrales mayas',500.00,'2 horas','Sáb 10:00-12:00'),(33,28,'Recorrido Gastronómico del Mercado','Tour guiado por los puestos más emblemáticos del mercado con degustaciones incluidas',200.00,'1.5 horas','Lun-Sáb 9:00-13:00'),(34,28,'Compra de Ingredientes Locales','Acompañamiento para seleccionar los mejores ingredientes frescos y especias yucatecas',NULL,'1 hora','Lun-Sáb 7:00-15:00'),(35,29,'Visita Guiada El Rey','Recorrido con guía certificado INAH por las 47 estructuras del sitio y su historia',150.00,'1.5 horas','Lun-Dom 8:00-17:00'),(36,29,'Observación de Iguanas','Caminata tranquila para observar la colonia de iguanas que habita el sitio',NULL,'30 min','Lun-Dom 8:00-17:00'),(37,30,'Tour Arqueológico El Meco','Explora la pirámide más alta de la zona norte de Quintana Roo con guía local',120.00,'1 hora','Mar-Dom 8:00-16:00'),(38,31,'Recorrido San Miguelito + Museo Maya','Visita combinada a la zona arqueológica y el Museo Maya de Cancún',200.00,'2.5 horas','Mar-Dom 9:00-17:00'),(39,32,'Kayak en la Laguna','Paseo en kayak por los manglares de la laguna con avistamiento de aves',450.00,'2 horas','Lun-Dom 7:00-16:00'),(40,32,'Tour de Manglares en Lancha','Recorrido en lancha por los canales del manglar con guía naturalista local',600.00,'2.5 horas','Lun-Dom 8:00-15:00'),(44,35,'Avistamiento de Cocodrilos','Caminata guiada por el manglar para observar cocodrilos en su hábitat natural',NULL,'1 hora','Lun-Dom 7:00-10:00'),(45,35,'Paseo en Bicicleta por el Malecón','Renta de bici y recorrido guiado por el circuito del malecón y áreas verdes',150.00,'1.5 horas','Lun-Dom 6:00-19:00'),(46,36,'Cena Degustación Maya Contemporánea','Menú de 5 tiempos con ingredientes prehispánicos y técnicas modernas',850.00,'2 horas','Jue-Sáb 19:00-22:00');
