INSERT IGNORE INTO `evento` VALUES (1,4,7,'🐢 Protección de Tortugas Marinas','Únete a la vigilancia nocturna para proteger los nidos de tortuga marina. Capacitación incluida.','2026-02-14','20:00:00','ods','aprobada',NULL,1,'2026-02-07 17:51:11'),(2,4,7,'🏖️ Limpieza de Playa Delfines','Gran jornada de limpieza comunitaria. Traer guantes y gorra. Se proporcionan bolsas.','2026-02-21','07:00:00','ods','aprobada',NULL,1,'2026-02-07 17:51:11'),(3,4,8,'🌿 Reforestación Ombligo Verde','Plantaremos 200 árboles nativos. Únete a restaurar este pulmón de la ciudad.','2026-02-28','08:00:00','ods','aprobada',NULL,1,'2026-02-07 17:51:11'),(4,1,NULL,'🦀 Protección de Cangrejo Azul','Ayuda a proteger la temporada de desove del cangrejo azul en la zona de manglares. Actividad guiada por biólogos marinos.','2026-06-15','07:00:00','ods','aprobada','/uploads/1773947496388-384087.jpeg',1,'2026-02-07 17:51:11'),(5,2,NULL,'Festival Gastronómico','Degustación de platillos especiales con maridaje de vinos mexicanos.','2026-02-12','19:00:00','general','aprobada',NULL,1,'2026-02-07 17:51:11'),(6,3,5,'Tour de Luna Llena','Excursión especial nocturna a Isla Mujeres durante la luna llena.','2026-02-19','18:00:00','general','aprobada',NULL,1,'2026-02-07 17:51:11'),(7,2,NULL,'Limpieza de playa Delfines','Ayuda a limpiar la playa','2026-04-15','09:00:00','ods','aprobada',NULL,1,'2026-03-16 00:15:49'),(8,2,NULL,'Taller de reciclaje','Aprende a reciclar','2026-05-01','10:00:00','ods','aprobada',NULL,1,'2026-03-16 00:17:10'),(10,3,18,'Festival de Jazz en la Playa','Tres días de jazz en vivo con artistas nacionales e internacionales frente al mar caribeño','2026-04-25','18:00:00','general','aprobada','https://images.unsplash.com/photo-1514320291840-2e0a9bf2a9ae?w=800',1,'2026-03-18 22:00:32'),(11,2,14,'Noche de Mezcal y Gastronomía','Cata de mezcales artesanales maridados con platillos de cocina maya contemporánea','2026-04-12','20:00:00','general','aprobada','https://images.unsplash.com/photo-1551024709-8f23befc6f87?w=800',1,'2026-03-18 22:00:32'),(12,4,6,'Carrera por el Manglar','Carrera de 5K y 10K a través del manglar del Parque Kabah. Inscripción incluye playera y medalla','2026-05-10','07:00:00','general','aprobada','https://images.unsplash.com/photo-1571008887538-b36bb32f4571?w=800',1,'2026-03-18 22:00:32'),(13,4,NULL,'Liberación de Tortugas 2026','Participa en la liberación de crías de tortuga marina. Actividad educativa y de conservación','2026-06-15','18:30:00','ods','aprobada','https://images.unsplash.com/photo-1437622368342-7a3d73a34c8f?w=800',1,'2026-03-18 22:00:32'),(14,4,NULL,'Taller de Coral Gardening','Aprende a restaurar arrecifes de coral con biólogos marinos. Incluye snorkel y siembra de fragmentos','2026-05-22','09:00:00','ods','aprobada','https://images.unsplash.com/photo-1546026423-cc4642628d2b?w=800',1,'2026-03-18 22:00:32'),(15,2,28,'🍽️ Festival Gastronómico del Mercado 23','Degustación de platillos tradicionales yucatecos y quintanarroenses preparados por los locatarios del mercado. Música en vivo y talleres de cocina.','2026-04-18','10:00:00','general','aprobada',NULL,1,'2026-03-19 18:05:02'),(16,3,29,'🌅 Equinoccio de Primavera en El Rey','Celebración del equinoccio con recorrido guiado especial, explicación arqueoastronómica y danza prehispánica. Cupo limitado.','2026-03-21','06:30:00','general','aprobada',NULL,1,'2026-03-19 18:05:02'),(17,4,32,'🌿 Limpieza de Manglar en Nichupté','Jornada comunitaria de limpieza del manglar y recolección de residuos. Se proporcionan guantes, bolsas y kayaks. ¡Ayuda a proteger nuestro ecosistema!','2026-04-22','07:00:00','ods','aprobada',NULL,1,'2026-03-19 18:05:02'),(18,4,NULL,'🦩 Avistamiento de Aves en Isla Blanca','Recorrido guiado por biólogos locales para observar flamencos, pelícanos y más de 30 especies de aves migratorias. Lleva binoculares.','2026-05-10','06:00:00','ods','aprobada',NULL,1,'2026-03-19 18:05:02'),(19,2,NULL,'🎨 Expo de Artistas Cancunenses','Exposición colectiva de pintores, escultores y fotógrafos locales de Cancún. Venta directa de obra, música en vivo y talleres para niños.','2026-04-05','11:00:00','general','aprobada',NULL,1,'2026-03-19 18:05:02'),(20,4,35,'🌱 Reforestación del Malecón Tajamar','Plantación de mangles y árboles nativos para restaurar el ecosistema del Tajamar. Actividad familiar con charla educativa sobre manglares.','2026-05-03','08:00:00','ods','aprobada',NULL,1,'2026-03-19 18:05:02'),(21,2,36,'🔥 Noche de Cocina Maya Ancestral','Cena especial con menú de 7 tiempos basado en recetas mayas prehispánicas. Maridaje con bebidas ceremoniales y explicación cultural de cada platillo.','2026-04-12','19:30:00','general','aprobada',NULL,1,'2026-03-19 18:05:02'),(22,2,24,'💀 Hanal Pixán - Día de Muertos Yucateco','Celebración del Hanal Pixán con altar tradicional, mucbipollo preparado bajo tierra y pan de muerto yucateco. Música de jarana.','2026-11-01','17:00:00','general','aprobada',NULL,1,'2026-03-19 18:05:02');
