INSERT IGNORE INTO `ubicacion` VALUES (2,2,'Tacos Rigo','Los mejores tacos de pastor y carnitas de Cancún. Auténtica comida callejera mexicana.',21.15916747,-86.83933281,'Av. Tulum 26, Centro',150.00,'998-234-5678','Lun-Sáb: 18:00-02:00','/uploads/1774446491140-237048.jpg','aprobada','2026-02-07 17:51:11'),(3,2,'Marakame Café','Café artesanal con granos locales. Ambiente bohemio perfecto para trabajar o relajarse.',21.14476306,-86.82974713,'Parque de las Palapas, Centro',100.00,'998-345-6789','Lun-Dom: 08:00-22:00','/uploads/1774446440671-624751.jpg','aprobada','2026-02-07 17:51:11'),(5,3,'Isla Mujeres Tour','Excursión en catamarán a Isla Mujeres. Incluye snorkel, barra libre y comida buffet.',21.25880000,-86.74020000,'Marina Aquatours, Blvd. Kukulcan',1500.00,'998-567-8901','Salidas: 09:00 y 10:30','/uploads/1774446400873-10602.jpeg','aprobada','2026-02-07 17:51:11'),(6,4,'Parque Kabah','Área natural protegida urbana. Hogar de coatíes, iguanas y aves. Senderos para caminar.',21.14189683,-86.83742365,'Av. Palenque s/n, SM 21',0.00,NULL,'Lun-Dom: 06:00-18:00','/uploads/1774446336504-532576.jpeg','aprobada','2026-02-07 17:51:11'),(7,4,'Playa Delfines','La playa pública más famosa de Cancún. Perfecta para ver atardeceres y tomar fotos en el letrero.',21.06148663,-86.77891745,'Blvd. Kukulcan Km 18, Zona Hotelera',0.00,NULL,'Abierta 24 horas','/uploads/1774446300721-490642.jpg','aprobada','2026-02-07 17:51:11'),(8,4,'Ombligo Verde','Reserva ecológica urbana con cenote. Importante zona de conservación de la biodiversidad local.',21.15657124,-86.84606591,'Av. La Luna, SM 46',50.00,'998-678-9012','Sáb-Dom: 09:00-15:00','/uploads/1774446230123-674135.jpeg','aprobada','2026-02-07 17:51:11'),(14,2,'Mercado 28','Mercado tradicional con artesanías, souvenirs y comida típica yucateca. Ideal para encontrar regalos y probar platillos locales.',21.16177844,-86.83424250,'Xel-Ha, SM 28, 77509 Cancún',150.00,'998 884 3478','Lun-Dom 8:00-20:00','/uploads/1774446182389-921762.jpg','aprobada','2026-03-18 21:59:43'),(15,4,'Parque de las Palapas','Plaza pública y centro cultural con eventos al aire libre, shows y comida callejera. Punto de encuentro de locales y turistas.',21.16116621,-86.82748888,'Av Tulum, SM 22, 77500 Cancún',0.00,NULL,'Abierto 24 horas','https://images.unsplash.com/photo-1506905925346-21bda4d32df4?w=800','aprobada','2026-03-18 21:59:43'),(18,3,'Playa Norte Isla Mujeres','Considerada una de las mejores playas del Caribe. Arena blanca, aguas cristalinas y ambiente relajado con restaurantes frente al mar.',21.22766206,-86.73260055,'Punta Norte, Isla Mujeres',300.00,NULL,'Abierto siempre','https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=800','aprobada','2026-03-18 21:59:43'),(19,4,'Museo Maya de Cancún','Museo arqueológico con más de 3,500 piezas de la civilización maya. Incluye zona arqueológica San Miguelito.',21.07384562,-86.77715745,'Blvd Kukulcán KM 16.5, Zona Hotelera',100.00,'998 885 3843','Mar-Dom 9:00-18:00','/uploads/1774446129389-969216.jpg','aprobada','2026-03-18 21:59:43'),(22,2,'Kiosko Verde Marisquería','Marisquería familiar fundada en 1974 por Don Eliseo Santiago. Reconocida por la Guía Michelin, es pionera del corredor gastronómico de Puerto Juárez. Especialidad en empanadas de langosta y pulpo zarandeado.',21.18674624,-86.80786259,'Av. López Portillo, Puerto Juárez',350.00,'998 884 2055','Mar-Dom 11:00-19:00','https://images.unsplash.com/photo-1615141982883-c7ad0e69fd62?w=800','aprobada','2026-03-18 22:26:49'),(23,3,'Lonchería Los Tres Reyes','La mejor cochinita pibil del centro de Cancún. Lonchería humilde pero siempre con fila. Tortas, tacos y kilos de cochinita con cebolla morada y habanero fresco.',21.17248207,-86.82919320,'Av. Kinic 63, SM 63',80.00,NULL,'Lun-Sáb 7:00-14:00','https://images.unsplash.com/photo-1599974579688-8dbdd335c77f?w=800','aprobada','2026-03-18 22:26:49'),(24,2,'Emara Antojitos Yucatecos','Clásico de Cancún frente al Mercado 28. Los mejores tamales yucatecos de la ciudad: vaporcitos, colados y torteados. Pide la salsa fresca de habanero.',21.16194294,-86.83565293,'SM 28, frente a Mercado 28',60.00,NULL,'Lun-Sáb 7:00-15:00','https://images.unsplash.com/photo-1551504734-5ee1c4a1479b?w=800','aprobada','2026-03-18 22:26:49'),(25,3,'La Parrilla Cancún','Restaurante familiar cancunense con más de 30 años sirviendo cocina mexicana. Mariachis en vivo, sopa de lima, cochinita pibil y queso relleno en un ambiente colorido y acogedor.',21.16356589,-86.82930398,'Av. Yaxchilán 51, SM 22',250.00,'998 287 8118','Lun-Dom 12:00-23:00','https://images.unsplash.com/photo-1625938146369-adc83368bda7?w=800','aprobada','2026-03-18 22:26:49'),(27,2,'El Fish Fritanga','Desde 2004, favorito de locales por su sazón casera frente a la Laguna Nichupté. Pescadillas, ceviches, camarones coco y el clásico pescado Tikin Xik.',21.10556197,-86.76445144,'Blvd Kukulcán KM 12.5, Zona Hotelera',280.00,'998 840 6210','Lun-Dom 11:00-21:00','https://images.unsplash.com/photo-1579631542720-3a87824fff86?w=800','aprobada','2026-03-18 22:26:49'),(28,4,'Mercado 23','El mercado más auténtico de Cancún desde los inicios de la ciudad. Frutas, verduras, fondas con cochinita pibil a $60 pesos, florerías y artesanías. Donde desayunan los cancunenses.',21.16800561,-86.82788581,'SM 23, Centro',50.00,NULL,'Lun-Dom 6:00-18:00','https://images.unsplash.com/photo-1533900298318-6b8da08a523e?w=800','aprobada','2026-03-18 22:26:49'),(29,4,'Zona Arqueológica El Rey','Sitio arqueológico maya en plena Zona Hotelera. Templos y plataformas rodeados de palmeras e iguanas. Una ventana a la vida cotidiana de los antiguos mayas sin salir de Cancún.',21.05943420,-86.78154411,'Blvd Kukulcán KM 18, Zona Hotelera',60.00,NULL,'Lun-Dom 8:00-17:00','https://images.unsplash.com/photo-1518638150340-f706e86654de?w=800','aprobada','2026-03-18 22:26:49'),(30,3,'Zona Arqueológica El Meco','Una de las pocas zonas arqueológicas dentro de Cancún. Conserva El Castillo, un basamento piramidal con vista al mar. Puerto comercial maya del período posclásico.',21.21099331,-86.80418816,'Carretera Puerto Juárez-Punta Sam KM 2.5',60.00,NULL,'Mar-Dom 8:00-16:30','/uploads/1774445912990-626069.jpg','aprobada','2026-03-18 22:26:49'),(31,4,'Zona Arqueológica San Miguelito','Asentamiento maya dedicado a producción de sal, miel y algodón. Cuatro conjuntos arquitectónicos junto al Museo Maya. Se accede con el boleto del museo.',21.07083967,-86.77886044,'Blvd Kukulcán KM 16.5, Zona Hotelera',95.00,NULL,'Mar-Dom 9:00-18:00','/uploads/1774445962773-278730.jpg','aprobada','2026-03-18 22:26:49'),(32,3,'Laguna Nichupté','Sistema lagunar de 3,000 hectáreas entre el centro de Cancún y la Zona Hotelera. Manglares, kayak, paddleboard y observación de aves. El pulmón verde de la ciudad.',21.07984369,-86.77596503,'Zona Hotelera',0.00,NULL,'Abierto siempre','/uploads/1774446025573-625995.jpeg','aprobada','2026-03-18 22:26:49'),(35,2,'Parque Cancún (Malecón Tajamar)','Malecón con vista a la laguna, ciclopista, áreas verdes y food trucks locales. Punto de reunión de familias cancunenses los fines de semana. Atardeceres espectaculares.',21.14711509,-86.81450045,'Blvd Luis Donaldo Colosio, SM 16',0.00,NULL,'Abierto 24 horas','/uploads/1774446093607-494187.jpeg','aprobada','2026-03-18 22:26:49'),(36,3,'Xkat-ik Restaurante','Cocina yucateca de autor. Especialidades: Tikin-xic, queso relleno Edam, panuchos y salbutes preparados con recetas familiares. Ambiente íntimo y servicio personalizado.',21.07477238,-86.77825332,'Av. Bonampak, SM 3',300.00,'998 213 4580','Mar-Dom 13:00-22:00','https://images.unsplash.com/photo-1414235077428-338989a2e8c0?w=800','aprobada','2026-03-18 22:26:49'),(37,2,'Las Originales de la Palenque','Popular local de ensaladas y comida saludable ubicado sobre la Avenida Palenque en el centro de Cancún. Ofrece ensaladas frescas, frutas y opciones ligeras con ingredientes frescos, siendo un favorito entre los locales que buscan opciones nutritivas y accesibles.',21.16288201,-86.83920339,'Av. Palenque Mz 2, SM 29, esquina Playa Caleta, 77508 Cancún, Q.R.',80.00,'+52 998 898 0929','Lunes a sábado 08:00 - 18:00. Domingos cerrado.','/uploads/1774447301667-825464.jpeg','aprobada','2026-03-22 23:35:42'),(38,2,'La Tranquita Restaurante Bar & Grill','Restaurante-bar con ambiente relajado ubicado sobre la Avenida Kabah en el centro de Cancún, especializado en carnes al carbón, pizzas a la leña y pastas. Cuenta con terraza al aire libre, música en vivo y transmisión de eventos deportivos, siendo un punto de encuentro ideal para reuniones sociales.',21.13785937,-86.83208064,'Av. Kabah S/N, Mz 1, Lote 22, SM 13, Plaza Zona Zentro, 77500 Cancún, Q.R.',200.00,'+52 998 802 1841','Lunes a miércoles 13:30 - 23:00; Jueves y viernes 13:30 - 00:30; Sábado 13:30 en adelante.','/uploads/1774447178516-625860.jpg','aprobada','2026-03-22 23:35:42'),(39,13,'Casa de Cultura de Cancún','Centro cultural público fundado en 1991, dedicado a la promoción artística y cultural de la comunidad cancunense. Ofrece talleres de danza, música, pintura, teatro y cerámica, además de albergar exposiciones, conciertos y eventos culturales en sus diversas salas y foros.',21.15244578,-86.83346094,'Prolongación Yaxchilán S/N, esquina SM 21, C.P. 77505, Benito Juárez, Q.R.',0.00,'998 884 8229','Lunes a viernes 08:30 - 21:00; Sábado 09:00 - 14:00.','/uploads/1774447438567-448367.jpg','aprobada','2026-03-22 23:35:42'),(40,13,'Teatro de la Ciudad de Benito Juárez','Moderno recinto cultural inaugurado en septiembre de 2024 tras una inversión de 135 millones de pesos, ubicado dentro del Centro Cultural de las Artes. Cuenta con un teatro principal con capacidad para 650 personas y un escenario secundario para 100 espectadores, equipado con tecnología de última generación en acústica e iluminación.',21.15194620,-86.82551646,'Av. Chichén Itzá S/N, SM 20, Mz 8, Lt 34, Centro, C.P. 77500, Benito Juárez, Q.R.',150.00,'998 898 4510','Oficinas: lunes a sábado 09:00 - 17:00. Funciones según programación.','/uploads/1774447539867-690520.jpg','aprobada','2026-03-22 23:35:42'),(41,4,'Jardín del Arte','Espacio cultural y recreativo al aire libre inaugurado en 2005 con apoyo de FONATUR, ubicado a orillas de la laguna Nichupté en la Zona Hotelera. Cuenta con un corredor de 600 metros adornado con esculturas, jardines y palapas, perfecto para disfrutar atardeceres espectaculares sobre la laguna.',21.14284404,-86.78316368,'Blvd. Kukulcán Km 4.5, Zona Hotelera, 77500 Cancún, Q.R.',0.00,NULL,'Acceso libre las 24 horas. Horario recomendado: 17:00 - 19:00 para el atardecer.','/uploads/1774447073052-117886.jpg','aprobada','2026-03-22 23:35:42'),(42,13,'Ka\'Yok\' Planetario de Cancún','Primer planetario en México con tecnología de quinta generación y décimo en el mundo con este nivel de equipamiento científico, inaugurado en 2013. Alberga un observatorio con telescopio de 16 pulgadas y el Museo del Agua Ch\'ooj K\'uun, ofreciendo una experiencia educativa única sobre astronomía y ciencia.',21.15305632,-86.83312339,'Av. Palenque S/N, SM 21, Mz 5, Lote 1, C.P. 77505, Cancún, Q.R.',50.00,'998 883 9557','Lunes a viernes 09:00 - 19:00; Días festivos 10:00 - 19:00.','/uploads/1774445408581-676228.png','aprobada','2026-03-22 23:35:42'),(43,14,'Museo de Cera de Cancún','Museo interactivo inaugurado en enero de 2016, ubicado en el segundo piso de Plaza La Isla Shopping Village en la Zona Hotelera. Exhibe más de 100 figuras de cera de personajes célebres del ámbito musical, televisión, política y terror, distribuidos en más de 25 escenarios temáticos.',21.11023764,-86.76350077,'Blvd. Kukulcán Km 12.5, Plaza La Isla Shopping Village, Zona Hotelera, 77500 Cancún, Q.R.',250.00,NULL,'Todos los días 10:00 - 22:00.','/uploads/1774447624898-553846.jpeg','aprobada','2026-03-22 23:35:42'),(44,2,'La Taberna de los Amigos','Sports bar y grill establecido en 1998, con pantalla gigante y más de 30 televisores para disfrutar eventos deportivos en vivo. Ofrece amplio menú de comida americana y mexicana, mesas de billar, juegos de mesa y un ambiente animado ideal para reuniones con amigos.',21.15065838,-86.84659931,'Av. del Sol, SM 44, Mz 1, Lote 9, 77507 Cancún, Q.R.',180.00,'+52 998 206 2006','Todos los días 12:00 - 02:00.','/uploads/1774447712664-115562.jpg','aprobada','2026-03-22 23:35:42'),(45,3,'MUSA - Museo Subacuático de Arte','Museo submarino único en el mundo, inaugurado en 2010, que alberga más de 500 esculturas sumergidas entre 3 y 6 metros de profundidad en el Parque Nacional Marino de Cancún. Se puede visitar mediante snorkel, buceo o en embarcaciones con fondo de cristal, combinando arte contemporáneo con la conservación de arrecifes de coral.',21.19923392,-86.72662968,'Blvd. Kukulcán Km 10.3, Punta Cancún, Zona Hotelera, C.P. 77500, Cancún, Q.R.',500.00,'998 848 8312','Lunes a domingo 09:00 - 17:00 (solo con servicios contratados de snorkel o buceo).','/uploads/1774447777563-890271.jpg','aprobada','2026-03-22 23:35:42');
